#include <stdio.h>

int main(void) {
    int n, x, count = 0;
    if (scanf("%d", &n) != 1) return 0;

    for (int i = 0; i < n; i++) {
        if (scanf("%d", &x) != 1) return 0;
        if (x >= 10 && x <= 50) {
            count++;
        }
    }

    printf("%d\n", count);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n, delta;
    long long balance = 0;
    if (scanf("%d", &n) != 1) return 0;

    for (int i = 1; i <= n; i++) {
        if (scanf("%d", &delta) != 1) return 0;
        balance += delta;
        if (balance >= 0) {
            printf("%d\n", i);
            return 0;
        }
    }

    printf("-1\n");
    return 0;
}

#include <stdio.h>

int main(void) {
    unsigned long long x;
    int sum = 0;
    if (scanf("%llu", &x) != 1) return 0;

    if (x == 0) {
        printf("0\n");
        return 0;
    }

    while (x > 0) {
        int digit = (int)(x % 10);
        if (digit % 2 == 0) {
            sum += digit;
        }
        x /= 10;
    }

    printf("%d\n", sum);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n, t;
    int current = 0, best = 0;
    if (scanf("%d", &n) != 1) return 0;

    for (int i = 0; i < n; i++) {
        if (scanf("%d", &t) != 1) return 0;
        if (t >= 30) {
            current++;
            if (current > best) best = current;
        } else {
            current = 0;
        }
    }

    printf("%d\n", best);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n, x;
    long long product = 1;
    if (scanf("%d", &n) != 1) return 0;

    for (int i = 0; i < n; i++) {
        if (scanf("%d", &x) != 1) return 0;
        if (x > 0 && x % 2 != 0) {
            product *= x;
        }
    }

    printf("%lld\n", product);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n, x, prev, count = 0;
    if (scanf("%d", &n) != 1) return 0;
    if (n <= 0) {
        printf("0\n");
        return 0;
    }

    if (scanf("%d", &prev) != 1) return 0;
    count = 1;

    for (int i = 1; i < n; i++) {
        if (scanf("%d", &x) != 1) return 0;
        if (x != prev) {
            count++;
        }
        prev = x;
    }

    printf("%d\n", count);
    return 0;
}

#include <stdio.h>

int main(void) {
    int x;
    long long sum = 0;

    while (scanf("%d", &x) == 1) {
        if (x < 0) break;
        sum += x;
    }

    printf("%lld\n", sum);
    return 0;
}

#include <stdio.h>
#include <math.h>

int main(void) {
    int n, x, best = -1;
    if (scanf("%d", &n) != 1) return 0;

    for (int i = 0; i < n; i++) {
        if (scanf("%d", &x) != 1) return 0;
        if (x > 1) {
            int prime = 1;
            for (int d = 2; d <= (int)sqrt((double)x); d++) {
                if (x % d == 0) {
                    prime = 0;
                    break;
                }
            }
            if (prime && x > best) {
                best = x;
            }
        }
    }

    printf("%d\n", best);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n, x;
    long long total = 0;
    if (scanf("%d", &n) != 1) return 0;

    for (int i = 1; i <= n; i++) {
        if (scanf("%d", &x) != 1) return 0;
        if (i % 2 == 1) {
            total += x;
        } else {
            total -= x;
        }
    }

    printf("%lld\n", total);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n, prev, x, count = 0;
    if (scanf("%d", &n) != 1) return 0;
    if (n <= 0) {
        printf("0\n");
        return 0;
    }

    if (scanf("%d", &prev) != 1) return 0;

    for (int i = 1; i < n; i++) {
        if (scanf("%d", &x) != 1) return 0;
        if (x > prev) {
            count++;
        }
        prev = x;
    }

    printf("%d\n", count);
    return 0;
}
